def predict(triples: list[Triple]) -> str:
    """Generate a fluent natural‑language sentence from a list of Triple objects."""
    if not triples:
        return ""
    # Mapping from predicate to a rendering function.
    # The function receives (subject, object, first) where first indicates if the subject
    # should be explicitly mentioned (used for the first clause of a subject group).
    def phrase(subject: str, predicate: str, obj: str, first: bool) -> str:
        # Helper to add article where appropriate
        def article(word: str) -> str:
            return "an " + word if word[0].lower() in "aeiou" else "a " + word
        if predicate == "country":
            return f"{subject} is based in {obj}" if first else f"is based in {obj}"
        if predicate == "foundingDate":
            return f"{subject} was founded on {obj}" if first else f"was founded on {obj}"
        if predicate == "foundationPlace":
            return f"{subject} was founded in {obj}" if first else f"was founded in {obj}"
        if predicate == "industry":
            return f"{subject} operates in the {obj}" if first else f"operates in the {obj}"
        if predicate == "city":
            return f"{subject} is headquartered in {obj}" if first else f"is headquartered in {obj}"
        if predicate == "regionServed":
            return f"{subject} serves {obj}" if first else f"serves {obj}"
        if predicate == "areaTotal":
            return f"{subject} covers an area of {obj}" if first else f"covers an area of {obj}"
        if predicate == "populationTotal":
            return f"{subject} has a population of {obj}" if first else f"has a population of {obj}"
        if predicate == "populationDensity":
            return f"{subject} has a population density of {obj}" if first else f"has a population density of {obj}"
        if predicate in {"netIncome", "operatingIncome", "revenue"}:
            return f"{subject}'s {predicate} is {obj}" if first else f"{predicate} is {obj}"
        if predicate == "leader":
            return f"The leader of {subject} is {obj}" if first else f"is led by {obj}"
        if predicate == "leaderTitle":
            return f"The leader of {subject} holds the title {obj}" if first else f"holds the title {obj}"
        if predicate == "leaderParty":
            return f"The leader of {subject} belongs to the {obj}" if first else f"belongs to the {obj}"
        if predicate == "officialLanguage":
            return f"{subject}'s official language is {obj}" if first else f"official language is {obj}"
        if predicate == "language":
            return f"{subject} speaks {obj}" if first else f"speaks {obj}"
        if predicate == "capital":
            return f"The capital of {subject} is {obj}" if first else f"is {obj}"
        if predicate == "motto":
            return f"{subject}'s motto is \"{obj}\"" if first else f"motto is \"{obj}\""
        if predicate == "type":
            return f"{subject} is a {obj}" if first else f"is a {obj}"
        if predicate == "service":
            return f"{subject} provides {obj}" if first else f"provides {obj}"
        if predicate == "product":
            return f"{subject} produces {obj}" if first else f"produces {obj}"
        if predicate == "subsidiary":
            return f"{subject} owns {obj}" if first else f"owns {obj}"
        if predicate == "parentCompany":
            return f"{subject} is a subsidiary of {obj}" if first else f"is a subsidiary of {obj}"
        if predicate == "location":
            return f"{subject} is located in {obj}" if first else f"is located in {obj}"
        if predicate == "timeZone":
            return f"{subject} lies in the {obj}" if first else f"lies in the {obj}"
        if predicate == "isPartOf":
            return f"{subject} is part of {obj}" if first else f"is part of {obj}"
        if predicate == "part":
            return f"{subject} includes {obj}" if first else f"includes {obj}"
        if predicate == "areaUrban":
            return f"{subject} has an urban area of {obj}" if first else f"has an urban area of {obj}"
        if predicate == "percentageOfAreaWater":
            return f"{obj}% of {subject}'s area is water" if first else f"is {obj}% water"
        # Fallback generic rendering
        return f"{subject} {predicate} {obj}" if first else f"{predicate} {obj}"
    # Group triples by subject to allow smoother combination.
    from collections import defaultdict
    groups = defaultdict(list)
    for t in triples:
        groups[t.subject].append(t)
    subject_clauses = []
    for subj, tlist in groups.items():
        # Render each triple; first clause keeps subject, others omit it.
        for i, t in enumerate(tlist):
            first = (i == 0)
            subject_clauses.append(phrase(t.subject, t.predicate, t.object, first))
    # Combine all clauses into a single fluent sentence.
    if len(subject_clauses) == 1:
        sentence = subject_clauses[0]
    else:
        sentence = ", ".join(subject_clauses[:-1]) + ", and " + subject_clauses[-1]
    return sentence.rstrip() + "."

